// Helper to normalize whitespace and remove trailing newlines for comparison
std::string normalize_output(const std::string& s) {
    std::string temp = s;
    // Remove trailing whitespace
    while (!temp.empty() && (temp.back() == '
' || temp.back() == '' || temp.back() == ' ')) {
        temp.pop_back();
    }
    // Optional: Replace multiple newlines with single, trim leading/trailing space on lines
    std::string normalized_s;
    std::istringstream iss(temp);
    std::string line;
    while (std::getline(iss, line)) {
        // Trim whitespace from beginning and end of line
        size_t first = line.find_first_not_of(" 	
");
        if (std::string::npos == first) {
            line.clear();
        } else {
            size_t last = line.find_last_not_of(" 	
");
            line = line.substr(first, (last - first + 1));
        }
        if (!line.empty() || !normalized_s.empty()) { // Keep empty lines if not first
             if (!normalized_s.empty()) normalized_s += '
';
             normalized_s += line;
        }
    }
    return normalized_s;
}

